import * as React from 'react';
import { Form, Button, Input, FormSelector } from '@universe-design/react';

const layout = {
  labelCol: { span: 8 },
  wrapperCol: { span: 16 },
};
const tailLayout = {
  wrapperCol: { offset: 8, span: 16 },
};

export default () => {
  const onFinish = (values: any) => {
    console.log('Success:', values);
  };

  return (
    <div style={{ maxWidth: 600 }}>
      <Form layout="horizontal" {...layout} initialValues={{}} onFinish={onFinish}>
        <FormSelector<any, boolean> selector={({ isValidating }) => isValidating}>
          {isValidating => (
            <Form.ItemUI {...tailLayout}>
              <Button loading={isValidating} delay={200} type="primary" htmlType="submit">
                Submit
              </Button>
            </Form.ItemUI>
          )}
        </FormSelector>
        {Array(1000)
          .fill(0)
          .map((_, index) => (
            <Form.Item
              key={index}
              required
              label={index}
              name={index}
              validate={(value, name) => (value ? undefined : 'Please Input')}
            >
              <Input />
            </Form.Item>
          ))}
      </Form>
    </div>
  );
};
